window.STEPS["'Users like you also bought…' Strip away the marketing language. Which algorithm is that recommender running?"] = [{"q":"'Users like you' means finding users whose tastes are…","ok":"Most similar to yours","no":["Most different from yours","Chosen at random"]},{"q":"Measuring how similar two users are by their histories is really a…","ok":"Distance between them","no":["Label for them","Vote count"]},{"q":"Recommending what those similar users liked is aggregating your…","ok":"Nearest neighbours' choices","no":["Own past choices only","Farthest users' choices"]},{"q":"So 'users like you also bought…' is really…","ok":"KNN over users","no":["A linear regression","A decision tree"]}];
