window.STEPS["You're building a production KNN system from scratch. Which order of steps is correct?"] = [{"q":"Distances need numbers, so text categories must first be…","ok":"Encoded into numbers","no":["Deleted","Left as words"]},{"q":"Once numeric, features must be put on one scale so none dominates — this is called…","ok":"Scaling","no":["Voting","Indexing"]},{"q":"Choosing k, the metric and weights should be decided on…","ok":"Honest validation data","no":["The training accuracy","The test set repeatedly"]},{"q":"A fast index (like a k-d tree) is a serving optimisation added…","ok":"Last","no":["First, before encoding","Instead of scaling"]},{"q":"So the correct order is…","ok":"Encode → scale → select → tune on CV → index","no":["Index → tune → scale → encode → select","Scale → encode → index → select → tune"]}];
